var e=[{id:`L2_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`괜찮아요? 에델!`,JPN:`大丈夫ですか、エデル！`,ENG:`Are you okay, Edel?`,TWN:`沒事吧？艾瑟兒！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`레, 레지나 님?`,JPN:`レ、レジーナ様？`,ENG:`M-Miss Regina?`,TWN:`蕾、蕾佳娜大人？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L6_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`지금...... 뭘 하신 거죠?`,JPN:`今……何をなさったんですか？`,ENG:`What did you just do now?`,TWN:`您……剛剛做了什麼？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`제단을 무너트렸어요! 이제 저 괴물의 힘도 약해질 거예요!`,JPN:`祭壇を壊しました！　これであの怪物の力も弱くなるはずです！`,ENG:`We've destroyed the altar! It'll weaken that monster!`,TWN:`我把祭壇破壞了！現在怪物的力量應該也變弱了！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`이길 수 있어요!`,JPN:`勝てますわ！`,ENG:`We can win this!`,TWN:`我們可以戰勝它的！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`분명 말씀하신 대로지만......`,JPN:`確かにおっしゃるとおりですが……`,ENG:`You're right about that...`,TWN:`我們之前也跟您說過……`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`저 제단은 강력한 힘을 통제하는 역할도 맡고 있답니다.`,JPN:`あの祭壇は強い力を統制する役割も担っているんです。`,ENG:`But that altar was also built to keep enormous energy under control.`,TWN:`那個祭壇也負責控制強大的力量。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`그런걸 마음대로 부숴버리게 되면......`,JPN:`それをむやみに壊してしまうと……`,ENG:`If that's no more, then...`,TWN:`如果隨便破壞它……`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`RIVET_ESPR_NULL_NULL`,text:{KOREA:`어...... 뭔가 불길한 소리가 들리는데?`,JPN:`あれ……何か嫌な音が聞こえるけど？`,ENG:`Erm... I hear something, and it doesn't sound good.`,TWN:`啊……好像聽到了什麼不祥的聲音耶？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`RIVET_ESPR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`무, 무슨 일이 벌어지는 거죠? 에델?`,JPN:`な、何が起こるのですか、エデル？`,ENG:`W-what’s going on, Edel?`,TWN:`發、發生什麼事情了？艾瑟兒？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`곧 차원 폭풍이 몰아칠 거에요.`,JPN:`間もなく次元の暴風が吹き荒れるでしょう。`,ENG:`A dimension storm is coming.`,TWN:`馬上就會吹起次元暴風。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`이 근처는 전부 초토화 되겠죠.`,JPN:`この辺りは焦土化するはずです。`,ENG:`This whole area will be wiped out.`,TWN:`這附近會化為一片焦土。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`도, 도망쳐요 다들!`,JPN:`に、逃げましょう！`,ENG:`R-run, everyone!`,TWN:`大、大家快逃！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`EDEL_ESPR_NULL_NULL`,text:{KOREA:`아. 이미 늦었네요. 휘말리겠어요.`,JPN:`ああ、もう手遅れですね。巻き込まれます。`,ENG:`Oh. It’s too late. We're getting swept away.`,TWN:`啊，已經太遲了，我們要被捲進去了。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`EDEL_ESPR_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L24_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`꺄아아아아악!!`,JPN:`きゃああぁぁぁぁぁっ！！`,ENG:`Eeeeek!`,TWN:`呀啊啊啊啊啊！！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`으음......`,JPN:`ううん……`,ENG:`Hngh...`,TWN:`嗯……`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:null,R:null}}}];export{e as default};